cssScope:
.med-report-card { font-family: sans-serif; background: #ffffff; border: 1px solid #dcdcdc; border-radius: 8px; padding: 20px; color: #2c3e50; max-width: 550px; margin: 15px 0; box-shadow: 0 4px 15px rgba(0,0,0,0.05); }
.med-header { text-align: center; border-bottom: 3px double #34495e; margin-bottom: 15px; padding-bottom: 12px; }
.med-title { font-size: 18px; font-weight: 900; color: #2c3e50; letter-spacing: 2px; }
.med-subtitle { font-size: 13px; color: #7f8c8d; margin-top: 5px; }
.med-patient-info { display: flex; flex-wrap: wrap; gap: 8px; font-size: 13px; margin-bottom: 15px; padding: 10px; background: #f8f9fa; border-radius: 4px; }
.med-patient-info span { width: 45%; font-weight: bold; }
.med-section-title { font-weight: bold; color: #2980b9; margin: 18px 0 10px; font-size: 14px; border-left: 4px solid #2980b9; padding-left: 8px; }
.med-highlight { color: #c0392b; border-left-color: #c0392b; }
.med-table { width: 100%; border-collapse: collapse; font-size: 13px; margin-bottom: 15px; }
.med-table td { border: 1px solid #e0e0e0; padding: 8px 10px; line-height: 1.4; }
.med-label { background: #ecf0f1; font-weight: bold; width: 30%; color: #34495e; }
.med-value { width: 70%; color: #333; }
.med-text-box { font-size: 13px; line-height: 1.6; padding: 12px; background: #fdfdfd; border: 1px dashed #bdc3c7; border-radius: 4px; color: #444; margin-bottom: 10px; }
.med-rx { background: #fffcf5; border-color: #f1c40f; color: #b78a00; }
.med-footer { font-size: 11px; color: #95a5a6; text-align: right; margin-top: 15px; border-top: 1px dashed #eee; padding-top: 10px; }

.sab-container {
  background: rgba(28, 22, 28, 0.75);
  border-radius: 16px;
  padding: 16px;
  border: 1px solid rgba(244, 63, 94, 0.25);
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.3);
  font-family: system-ui, -apple-system, sans-serif;
  max-width: 100%;
  box-sizing: border-box;
}
.sab-title {
  font-size: 16px;
  font-weight: bold;
  text-align: center;
  color: #fda4af;
  text-shadow: 0 0 10px rgba(244, 63, 94, 0.6);
  margin-bottom: 2px;
}
.sab-subtitle {
  font-size: 10px;
  text-align: center;
  color: #888;
  margin-bottom: 16px;
}
/* 核心网格重构：电脑端默认一排 4 个 */
.sab-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 10px;
}
.sab-card {
  background: rgba(255, 255, 255, 0.04);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 10px;
  padding: 10px 4px;
  display: flex;
  flex-direction: column;
  align-items: center;
  box-sizing: border-box;
  min-width: 0; /* 防止文本溢出撑开网格 */
  height: 100%; /* 保证同一行的卡片高度完美整齐 */
}
.sab-bottle-wrapper {
  display: flex;
  flex-direction: column;
  align-items: center;
  margin-bottom: 6px;
  width: 100%;
}
.sab-bottle-neck {
  width: 14px;
  height: 6px;
  border: 1.5px solid #d4d4d8;
  border-bottom: none;
  border-radius: 3px 3px 0 0;
  background: rgba(255, 255, 255, 0.15);
}
.sab-bottle-body {
  width: 32px;
  height: 48px;
  border: 1.5px solid #d4d4d8;
  border-radius: 4px 4px 8px 8px;
  position: relative;
  overflow: hidden;
  background: rgba(255, 255, 255, 0.05);
  box-shadow: inset 0 0 6px rgba(255, 255, 255, 0.15);
}
.sab-fluid {
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  background: linear-gradient(to top, #e11d48, #fb7185);
  border-top: 1px solid #ffe4e6;
  border-radius: 0 0 6px 6px;
  transition: height 0.6s cubic-bezier(0.4, 0, 0.2, 1);
}
.sab-highlight {
  position: absolute;
  top: 0;
  left: 2px;
  width: 4px;
  height: 100%;
  background: rgba(255, 255, 255, 0.12);
  border-radius: 2px;
  pointer-events: none;
}
.sab-score-badge {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  font-size: 9px;
  font-weight: bold;
  color: #fff;
  text-shadow: 1px 1px 2px rgba(0,0,0,0.9), -1px -1px 2px rgba(0,0,0,0.9);
  z-index: 5;
}
.sab-info {
  text-align: center;
  width: 100%;
}
.sab-name {
  font-size: 11px;
  font-weight: bold;
  color: #f4f4f5;
  margin-bottom: 4px;
  word-break: break-word;
}
.sab-comment {
  font-size: 9px;
  color: #a1a1aa;
  line-height: 1.3;
  word-break: break-all;
  padding: 0 2px;
}

/* ================= 手机端专属响应式优化 ================= */
@media (max-width: 600px) {
  .sab-grid {
    /* 【修改这里可以调整列数】默认 repeat(4, 1fr) 代表一排4个（28个刚好7行，无余数） */
    /* 如果你觉得一排4个格子有点挤、文字太长，可以把它改成 repeat(2, 1fr) 变成一排2个（刚好14行，也无余数） */
    grid-template-columns: repeat(4, 1fr); 
    gap: 6px; /* 适当减小手机端的间距 */
  }
  .sab-card {
    padding: 6px 2px;
  }
  .sab-bottle-body {
    width: 24px;  /* 略微缩小手机端的瓶子，给文本留出足够空间 */
    height: 38px;
  }
  .sab-bottle-neck {
    width: 10px;
    height: 4px;
  }
  .sab-score-badge {
    font-size: 8px;
  }
  .sab-name {
    font-size: 9.5px;
    white-space: normal; /* 允许项目名称长的时候换行（如传教士体位） */
  }
  .sab-comment {
    font-size: 8.5px;
    line-height: 1.2;
    /* 彻底解除老版本的盒子截断，让文本自然流出、自动撑开卡片高度 */
    display: block;
    overflow: visible;
    -webkit-line-clamp: unset;
    max-height: none;
  }
}

